MenuData menuDataFromJson(String str) => MenuData.fromJson(json.decode(str));
String menuDataToJson(MenuData data) => json.encode(data.toJson());
class MenuData {
  MenuData({
      List<AllDayMenu>? allDayMenu, 
      List<MorningMenu>? morningMenu,}){
    _allDayMenu = allDayMenu;
    _morningMenu = morningMenu;
}

  MenuData.fromJson(dynamic json) {
    if (json['all_day_menu'] != null) {
      _allDayMenu = [];
      json['all_day_menu'].forEach((v) {
        _allDayMenu?.add(AllDayMenu.fromJson(v));
      });
    }
    if (json['morning_menu'] != null) {
      _morningMenu = [];
      json['morning_menu'].forEach((v) {
        _morningMenu?.add(MorningMenu.fromJson(v));
      });
    }
  }
  List<AllDayMenu>? _allDayMenu;
  List<MorningMenu>? _morningMenu;
MenuData copyWith({  List<AllDayMenu>? allDayMenu,
  List<MorningMenu>? morningMenu,
}) => MenuData(  allDayMenu: allDayMenu ?? _allDayMenu,
  morningMenu: morningMenu ?? _morningMenu,
);
  List<AllDayMenu>? get allDayMenu => _allDayMenu;
  List<MorningMenu>? get morningMenu => _morningMenu;

  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    if (_allDayMenu != null) {
      map['all_day_menu'] = _allDayMenu?.map((v) => v.toJson()).toList();
    }
    if (_morningMenu != null) {
      map['morning_menu'] = _morningMenu?.map((v) => v.toJson()).toList();
    }
    return map;
  }

}

